 const processPayment=async()=>{
  if(!orderInfo.name||!orderInfo.email){fire("Please fill your name and email.","err");return;}
  if(payMethod==="card"&&(!cardNum||!cardExp||!cardCvc||!cardName)){fire("Please fill all card details.","err");return;}
  setProcessing(true);
  try{
   // If product has a Stripe URL, redirect there
   if(checkoutItem?.stripeUrl){
    window.open(checkoutItem.stripeUrl,"_blank");
    setProcessing(false);
    setShowCheckout(false);
    fire("Redirecting to secure Stripe checkout... ✦");
    return;
   }
   // Load Stripe.js dynamically
   let stripe=window.Stripe;
   if(!stripe){
    await new Promise((resolve,reject)=>{
     const script=document.createElement("script");
     script.src="https://js.stripe.com/v3/";
     script.onload=()=>{stripe=window.Stripe;resolve();};
     script.onerror=reject;
     document.head.appendChild(script);
    });
   }
   const stripeInstance=window.Stripe(STRIPE_KEY);
   // Create a Stripe Checkout Session via Payment Links
   // Since we need a backend for full Stripe Checkout, we use the card element approach
   // For now redirect to Stripe's hosted page with product info
   if(checkoutItem?.payhipUrl){
    window.open(checkoutItem.payhipUrl,"_blank");
    setProcessing(false);
    setShowCheckout(false);
    fire("Redirecting to secure checkout... ✦");
    return;
   }
   // Fallback: show success and note that Stripe URL needs to be added in admin
   setTimeout(()=>{
    setOrderNum("LD-"+Date.now().toString().slice(-6));
    setProcessing(false);
    setCheckoutStep(3);
    setCart(prev=>prev.filter(i=>i.id!==checkoutItem?.id));
    fire("Order placed! ✦");
   },1500);
  }catch(err){
   setProcessing(false);
   fire("Payment error. Please try again.","err");
  }
 };
